SELECT DISTINCT battle_id
FROM move_usage
WHERE turn_number = 1;

SELECT COUNT(*) AS total_usage
FROM move_usage
WHERE move_id = 1;

SELECT COUNT(*) AS total_move_histories
FROM move_histories
WHERE user_id = 1;

SELECT AVG(power) AS average_power
FROM moves
WHERE move_type = 'Poison';

SELECT pokemon_name
FROM pokemon
WHERE base_attack = (SELECT MAX(base_attack) FROM pokemon);

SELECT COUNT(battle_id) AS total_battles
FROM battles
WHERE pokemon_id = 1;

SELECT move_name
FROM moves
ORDER BY move_name ASC;

SELECT pokemon_name
FROM pokemon
ORDER BY pokemon_name ASC;
